    print(f'Params: {[p[0] for p in params_list]}')
    print(f'PS keys: {ps_keys}')
    print(f'SS keys: {ss_keys}')

    resolved = {}
    for path, decl in params_list:
        val, src = resolve_parameter(path, decl, [], None, None)
        print(f'{path} = {val} (from {src})')
        resolved[path] = val

    output = build_output(params_list, resolved)
    print(json.dumps(output))
finally:
    os.unlink(schema_path)
